import pytest
from canoe import CanoeAPI

@pytest.fixture
def canoe_setup():
    # Initialize CANoe API and setup the simulation environment
    api = CanoeAPI()
    api.connect()
    return api

class TestBcmHazardLightStatus:
    @pytest.mark.parametrize("test_case", [
        {"test_id": "TC_001", "name": "Hazard Light On - Positive Test Case"},
        {"test_id": "TC_002", "name": "Hazard Light Off - Positive Test Case"},
        {"test_id": "TC_003", "name": "Hazard Light Status - Edge Case Test"},
        {"test_id": "TC_004", "name": "CAN Bus Failure - Negative Test Case"},
        {"test_id": "TC_005", "name": "ECU Reset - Timing/Sequence Test"},
        {"test_id": "TC_006", "name": "Hazard Light Status - Timing/Sequence Test"}
    ])
    def test_hazard_light_status(self, canoe_setup, test_case):
        # Set up the simulation environment
        api = canoe_setup
        api.reset()

        # Perform preconditions
        for precondition in test_case["preconditions"]:
            if precondition == "ECU initialized":
                api.ecu_init()
            elif precondition == "CAN bus active":
                api.canoe_set_mode("CYCLIC")
            else:
                raise ValueError(f"Unknown precondition: {precondition}")

        # Perform test steps
        for step in test_case["steps"]:
            if step["action"] == "Turn Hazard Lights On":
                msg = {"Hazard_Light_Status": 1}
                api.send_message("BCM_Status_1", msg)
            elif step["action"] == "Turn Hazard Lights Off":
                msg = {"Hazard_Light_Status": 0}
                api.send_message("BCM_Status_1", msg)
            elif step["action"] == "Check CAN Bus for BCM Status Message":
                received_messages = api.get_received_messages()
                assert len(received_messages) > 0
                assert received_messages[0]["message_id"] == "BCM_Status_1"
                assert received_messages[0]["data"]["Hazard_Light_Status"] == step["value"]
            elif step["action"] == "Check CAN Bus for BCM Status Message after Reset":
                # Wait for the ECU to reset
                api.wait_for_ecu_reset()
                received_messages = api.get_received_messages()
                assert len(received_messages) > 0
                assert received_messages[0]["message_id"] == "BCM_Status_1"
                assert received_messages[0]["data"]["Hazard_Light_Status"] == step["value"]
            else:
                raise ValueError(f"Unknown test step: {step}")

        # Perform assertions based on expected results
        for assertion in test_case["assertions"]:
            if assertion["expected_result"] == "BCM should transmit a valid message with hazard light status as 1":
                received_messages = api.get_received_messages()
                assert len(received_messages) > 0
                assert received_messages[0]["message_id"] == "BCM_Status_1"
                assert received_messages[0]["data"]["Hazard_Light_Status"] == 1
            elif assertion["expected_result"] == "BCM should transmit a valid message with hazard light status as 0":
                received_messages = api.get_received_messages()
                assert len(received_messages) > 0
                assert received_messages[0]["message_id"] == "BCM_Status_1"
                assert received_messages[0]["data"]["Hazard_Light_Status"] == 0
            else:
                raise ValueError(f"Unknown assertion: {assertion}")

