import pytest
from canoe import CanoeAPI

@pytest.fixture
def canoe_setup():
    return CanoeAPI()

class TestHeadlightControl:
    @pytest.mark.parametrize("test_case", [
        {"test_id": "TC_001", "name": "Normal Operation - Headlights On"},
        {"test_id": "TC_003", "name": "Edge Case - Vehicle Speed at Maximum"},
        {"test_id": "TC_004", "name": "Timing/Sequence Test - Headlight Turn-On Delay"},
        {"test_id": "TC_006", "name": "State Transition Test - Headlight Turn-On from Off"}
    ])
    def test_normal_operation(self, canoe_setup, test_case):
        # Send message to GW
        canoe_setup.send_message("GWS_Vehicle_Speed_Avg", 120)

        # Check headlight status
        msg = canoe_setup.get_received_messages()
        assert get_headlight_status(msg.data) == 1

    @pytest.mark.parametrize("test_case", [
        {"test_id": "TC_002", "name": "Error Condition - CAN Bus Fault"}
    ])
    def test_error_condition(self, canoe_setup, test_case):
        # Simulate CAN bus fault
        canoe_setup.simulate_can_bus_fault()

        # Send message to GW
        canoe_setup.send_message("GWS_Vehicle_Speed_Avg", 120)

        # Check error status
        msg = canoe_setup.get_received_messages()
        assert get_error_status(msg.data) == 1

    @pytest.mark.parametrize("test_case", [
        {"test_id": "TC_005", "name": "State Transition Test - Headlight Turn-Off"}
    ])
    def test_state_transition_off(self, canoe_setup, test_case):
        # Send message to GW
        canoe_setup.send_message("GWS_Vehicle_Speed_Avg", 0)

        # Check headlight status
        msg = canoe_setup.get_received_messages()
        assert get_headlight_status(msg.data) == 0

def get_headlight_status(data):
    return data["Headlight_Status"]

def get_error_status(data):
    return data["Error_Status"]
Note: The `get_headlight_status` and `get_error_status` functions are assumed to be implemented elsewhere in the codebase. They should take the message data as input and return the corresponding status value.

Also, the `canoe_setup` fixture is used to set up the CANoe API for each test case. The `send_message`, `simulate_can_bus_fault`, and `get_received_messages` functions are assumed to be part of the CANoe API.

