import time
from can import Bus

def simulate_vehicle_speed(can_bus, speed):
    # Simulate vehicle speed by sending a message to the CAN bus
    msg = can_bus.send('ECM_VehicleData', data={'VehicleSpeed': speed})

def collect_speed_messages(can_bus, timeout):
    # Collect messages from the CAN bus with the specified timeout
    start_time = time.time()
    while True:
        if time.time() - start_time > timeout:
            break
        for msg in can_bus.history(timeout=0.1):
            if 'ECM_VehicleData' in msg.arbitration_id and 'VehicleSpeed' in msg.data:
                yield msg

def extract_speed(msg):
    # Extract the vehicle speed from a message
    return msg.data['VehicleSpeed']

VEHICLE_SPEED_MAX = 260

def test_tc_vs_010_periodicity(can_bus):
    simulate_vehicle_speed(can_bus, 40)
    msgs = collect_speed_messages(can_bus, 2.0)
    assert len(msgs) >= 10

def test_tc_ecm_vs_007(can_bus):
    msgs = collect_ecm(can_bus)
    assert all(extract_speed(m) <= VEHICLE_SPEED_MAX for m in msgs)

def collect_ecm(can_bus):
    # Collect ECM messages from the CAN bus
    return [msg for msg in can_bus.history() if 'ECM' in msg.arbitration_id]

# Example usage:
if __name__ == '__main__':
    with Bus('vcan0', bustype='socketcan') as can_bus:
        test_tc_vs_010_periodicity(can_bus)
        test_tc_ecm_vs_007(can_bus)
