import can
import pytest
import time

MESSAGE_ID_GW_VEHICLE_STATUS = 0xC8
MESSAGE_ID_GW_WARNINGS = 0xD2

@pytest.fixture(scope="session")
def can_bus():
    bus = can.Bus(
        interface="socketcan",   # vector / pcan configurable
        channel="can0",
        bitrate=500000
    )
    yield bus
    bus.shutdown()

def collect_messages(bus, arb_id, duration_sec):
    messages = []
    start_time = time.time()
    while time.time() - start_time < duration_sec:
        msg = bus.recv(timeout=0.1)
        if msg and msg.arbitration_id == arb_id:
            messages.append(msg)
    return messages

def decode_gw_speedout(msg):
    """Extract GW_SpeedOut from CAN message. start_bit=0, length=16, little_endian"""
    return (msg.data[0] >> 0) & 0xFFFF  

def decode_anydooropen(msg):
    """Extract AnyDoorOpen from CAN message. start_bit=16, length=1, little_endian"""
    return (msg.data[2] >> 0) & 0x1

def decode_turnactive(msg):
    """Extract TurnActive from CAN message. start_bit=17, length=1, little_endian"""
    return (msg.data[2] >> 1) & 0x1

def decode_overspeedwarning(msg):
    """Extract OverspeedWarning from CAN message. start_bit=0, length=1, little_endian"""
    return (msg.data[0] >> 0) & 0x1

def decode_doorwarning(msg):
    """Extract DoorWarning from CAN message. start_bit=1, length=1, little_endian"""
    return (msg.data[0] >> 1) & 0x1

def test_tc_gw_vehicle_status_001_all_closed(can_bus):
    msgs = collect_messages(can_bus, MESSAGE_ID_GW_VEHICLE_STATUS, 2)
    assert msgs, "No GW_VehicleStatus messages received"
    for msg in msgs:
        assert decode_anydooropen(msg) == 0
        assert decode_turnactive(msg) == 0

def test_tc_gw_vehicle_status_002_one_door_open(can_bus):
    msgs = collect_messages(can_bus, MESSAGE_ID_GW_VEHICLE_STATUS, 2)
    assert msgs, "No GW_VehicleStatus messages received"
    for msg in msgs:
        assert decode_anydooropen(msg) == 1

def test_tc_gw_vehicle_status_003_multiple_doors_open(can_bus):
    msgs = collect_messages(can_bus, MESSAGE_ID_GW_VEHICLE_STATUS, 2)
    assert msgs, "No GW_VehicleStatus messages received"
    for msg in msgs:
        assert decode_anydooropen(msg) == 1

def test_tc_gw_warnings_001_no_warning(can_bus):
    msgs = collect_messages(can_bus, MESSAGE_ID_GW_WARNINGS, 2)
    assert msgs, "No GW_Warnings messages received"
    for msg in msgs:
        assert decode_overspeedwarning(msg) == 0
        assert decode_doorwarning(msg) == 0

def test_tc_gw_warnings_002_warning_present(can_bus):
