import time
from capl import CaplSimulator, CaplMessage

# Define constants
VEHICLE_SPEED_MAX = 100
CIRCLE_TIME = 1.0  # seconds

class TestCases:
    def __init__(self):
        self.can_bus = CaplSimulator()

    def simulate_vehicle_speed(self, can_bus, speed):
        # Simulate vehicle speed transmission
        msg_ecm_vehicle_data = CaplMessage('ECM_VehicleData')
        msg_ecm_vehicle_data.speed = speed
        can_bus.send_message(msg_ecm_vehicle_data)

    def collect_speed_messages(self, can_bus, cycle_time):
        # Collect speed messages from the CAN bus
        start_time = time.time()
        while True:
            msg_ecm_vehicle_data = can_bus.recv_message()
            if msg_ecm_vehicle_data.speed is not None and msg_ecm_vehicle_data.speed <= VEHICLE_SPEED_MAX:
                yield msg_ecm_vehicle_data
            time.sleep(cycle_time)

    def collect_ecm(self, can_bus):
        # Collect ECM messages from the CAN bus
        return [msg for msg in can_bus.recv_messages() if isinstance(msg, CaplMessage)]

def test_tc_vs_010_periodicity(can_bus):
    simulate_vehicle_speed(can_bus, 40)
    msgs = list(collect_speed_messages(can_bus, CIRCLE_TIME))
    assert len(msgs) >= 10

def test_tc_ecm_vs_007(can_bus):
    msgs = collect_ecm(can_bus)
    assert all(extract_speed(m) <= VEHICLE_SPEED_MAX for m in msgs)

# Define extract speed function
def extract_speed(m):
    if isinstance(m, CaplMessage) and hasattr(m, 'speed'):
        return m.speed
    else:
        raise ValueError('Invalid message format')

if __name__ == '__main__':
    test_cases = TestCases()
    test_tc_vs_010_periodicity(test_cases.can_bus)
    test_tc_ecm_vs_007(test_cases.can_bus)
Note that this code assumes the `capl` library is installed and imported correctly. Also, the `simulate_vehicle_speed`, `collect_speed_messages`, and `collect_ecm` functions are defined to mimic the behavior of the CAPL script. The `extract_speed` function is used to extract the speed value from ECM messages.

