class TestTCHB003TransitionOffToOn(Ragetests):
    def __init__(self):
        super().__init__()
        self.test_name = "test_tc_hb_003_transition_off_to_on"
        self.description = "Test that the system adjusts the interior light level when transitioning from day mode to night mode based on headlight status feedback."

    def test(self, can_bus):
        # Wait for next IC frame
        msg = wait_for_next_ic_frame(can_bus)
        assert get_high_beam_status(msg.data) == 1

def wait_for_next_bcm_message(can_bus):
    start_time = time.time()
    while True:
        if can_bus.is_available():
            return can_bus.recv()
        time.sleep(0.01)

def wait_for_next_ic_frame(can_bus):
    start_time = time.time()
    while True:
        if can_bus.is_available():
            return can_bus.recv()
        time.sleep(0.01)

def get_headlight_status(data):
    # Assuming the headlight status is stored in data[0:2]
    return data[0] + (data[1] << 8)

def get_high_beam_status(data):
    # Assuming the high beam status is stored in data[4:6]
    return data[4] + (data[5] << 8)
