import time
from can import CanBus, Message

# Define messages
class GW_OperationalPresence(Message):
    def __init__(self):
        super().__init__("GW_OperationalPresence", 0x1234)
        self.data = [0x00] * 8

class GW_IgnitionStatus(Message):
    def __init__(self):
        super().__init__("GW_IgnitionStatus", 0x5678)
        self.data = [0x00, 0x01]

class GW_VehicleSpeed(Message):
    def __init__(self):
        super().__init__("GW_VehicleSpeed", 0x9012)
        self.data = [0x00, 0x03]

# Define functions
def get_trunk_status(data):
    # Implementation of trunk status logic
    return data[1] == 0x01

def get_signal(data, signal_id):
    # Implementation of signal logic
    return data[signal_id] == 0x00

def wait_next_bcm_frame(can_bus):
    # Wait for next BCM frame
    start_time = time.time()
    while True:
        msg = can_bus.recv(timeout=1.0)
        if msg.is_valid and msg.timestamp > start_time:
            return msg

# Test cases
class TestGWDoor:
    def __init__(self, can_bus):
        self.can_bus = can_bus

    def test_tc_gw_door_001_all_closed(self):
        # Verification after manual ignition cycle
        msg = wait_next_bcm_frame(self.can_bus)
        assert get_signal(msg.data, 2) == 0

# Main function
def main():
    # Create CanBus object
    can_bus = CanBus()

    # Create test object
    test = TestGWDoor(can_bus)

    # Run tests
    test.test_tc_gw_door_001_all_closed()

if __name__ == "__main__":
    main()
