    assert msgs
    for msg in msgs:
        assert decode_anydooropen(msg) == 1

def test_tc_state_bcm_status_message_reception(can_bus):
    msgs = collect_messages(can_bus, MESSAGE_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_anydooropen(msg) == 1

