    """Decode CycleTime signal from Gateway_Status message."""
    return (msg.data[2] & 0xFF) + ((msg.data[3] & 0xFF) << 8)

def decode_sequence_number(msg):
    """Decode SequenceNumber signal from Gateway_Status message."""
    return msg.data[4]

