    // Read the relevant input signal(s)
    int doorFL = thisDoorFL;

    // Update the corresponding output signal(s) in the output message
    if (doorFL == 1 && msgBodyStatus.DoorFL == 0) {
        msgBodyStatus.DoorFL = 1;
    } else if (doorFL == 0 && msgBodyStatus.DoorFL == 1) {
        msgBodyStatus.DoorFL = 0;
    }

    // Call output(...) IMMEDIATELY in this handler
    output(msgBodyStatus);
}

