import can
import pytest
import time

MESSAGE_ID = 0x3EA

@pytest.fixture(scope="session")
def can_bus():
    bus = can.Bus(interface="socketcan", channel="can0", bitrate=500000)
    yield bus
    bus.shutdown()

def collect_messages(bus, arb_id, duration_sec):
    start = time.time()
    msgs = []
    while time.time() - start < duration_sec:
        msg = bus.recv(timeout=0.1)
        if msg and msg.arbitration_id == arb_id:
            msgs.append(msg)
    return msgs

def decode_alivecounter(msg):
    return (msg.data[0] >> 0) & 0xF

def test_tc_gateway_001(can_bus):
    # Validate AliveCounter initialization to 0 during Gateway power-up
    msgs = collect_messages(can_bus, MESSAGE_ID, 1.0)
    assert len(msgs) > 0
    assert decode_alivecounter(msgs[0]) == 0

def test_tc_gateway_002(can_bus):
    # Validate AliveCounter increment before each GW_Response message transmission
    msgs = collect_messages(can_bus, MESSAGE_ID, 1.0)
    assert len(msgs) > 4
    for i in range(1, 5):
        assert decode_alivecounter(msgs[i]) == decode_alivecounter(msgs[i-1]) + 1

def test_tc_gateway_003(can_bus):
    # Validate GW_Response message transmission period
    start_time = time.time()
    msgs = collect_messages(can_bus, MESSAGE_ID, 2.0)
    assert len(msgs) > 10
    for i in range(1, 10):
        assert (msgs[i].timestamp - msgs[i-1].timestamp) * 1000 >= 90 and (msgs[i].timestamp - msgs[i-1].timestamp) * 1000 <= 110

def test_tc_gateway_004(can_bus):
    # Validate AliveCounter reset to 0 after reaching maximum value
    msgs = collect_messages(can_bus, MESSAGE_ID, 5.0)
    assert len(msgs) > 15
    for msg in msgs:
        if decode_alivecounter(msg) == 15:
            next_msg = next((m for m in msgs[msgs.index(msg)+1:] if m.arbitration_id == MESSAGE_ID), None)
            if next_msg:
                assert decode_alivecounter(next_msg) == 0

def test_tc_gateway_005(can_bus):
    # Validate Instrument Cluster communication fault detection
    pytest.skip("Test case requires simulating a communication fault and verifying the Instrument Cluster's response, which is not possible with the given setup.")

